import React, { InputHTMLAttributes } from "react";

import { useStableId } from "../hooks/useStableId";
import styles from "./CyberpunkRadio.module.css";

export interface CyberpunkRadioProps extends InputHTMLAttributes<HTMLInputElement> {
  label?: string;
}

export function CyberpunkRadio({ label, className = "", id, ...props }: CyberpunkRadioProps) {
  const inputId = useStableId("radio", id);

  return (
    <label htmlFor={inputId} className={`${styles.wrapper} ${className}`.trim()}>
      <input id={inputId} type="radio" className={styles.radio} {...props} />
      {label ? <span className={styles.label}>{label}</span> : null}
    </label>
  );
}

export interface CyberpunkRadioGroupProps {
  name: string;
  options: { value: string; label: string }[];
  value?: string;
  onChange?: (value: string) => void;
  className?: string;
}

export function CyberpunkRadioGroup({
  name,
  options,
  value,
  onChange,
  className = "",
}: CyberpunkRadioGroupProps) {
  return (
    <div className={`${styles.radioGroup} ${className}`.trim()}>
      {options.map((option) => (
        <CyberpunkRadio
          key={option.value}
          name={name}
          value={option.value}
          label={option.label}
          checked={value === option.value}
          onChange={(event) => onChange?.(event.target.value)}
        />
      ))}
    </div>
  );
}

.wrapper {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  cursor: pointer;
  user-select: none;
}

.radio {
  width: 28px;
  height: 28px;
  border: 2px solid var(--border);
  border-radius: 50%;
  appearance: none;
  outline: none;
  margin: 0;
  cursor: pointer;
  position: relative;
  background-color: var(--bg-primary);
  transition: all var(--transition-fast);
}

.radio::before {
  content: "";
  width: 16px;
  height: 16px;
  background-color: var(--success);
  border-radius: 50%;
  position: absolute;
  top: 4px;
  left: 4px;
  display: block;
  transform: scale(0);
  transition: 120ms transform ease-in-out;
}

.radio:checked::before {
  transform: scale(1);
}

.radio:hover {
  border-color: var(--success);
}

.radio:focus-visible {
  box-shadow: 0 0 0 2px rgba(0, 255, 136, 0.2);
}

.radio:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.label {
  font-size: 0.875rem;
  color: var(--text-primary);
}

.radioGroup {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

import { useId } from "react";

export function useStableId(prefix: string, explicitId?: string): string {
  const reactId = useId().replace(/:/g, "");
  return explicitId || `${prefix}-${reactId}`;
}
